"AHA.Heart Failure Outpatient Encounter" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Care Services in Long Term Residential Facility" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Nursing Facility Visit" UNION SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Outpatient Consultation") AS QualifyingEncounter WHERE CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(QualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND fhirpath_text(QualifyingEncounter.resource, 'status') = 'finished' AND EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Condition: Heart Failure (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Heart Failure (qicore-condition-encounter-diagnosis)") AS HeartFailure WHERE intervalOverlaps(CASE WHEN fhirpath_text(HeartFailure.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')), fhirpath_text(HeartFailure.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, fhirpath_text(QualifyingEncounter.resource, 'period')) AND (fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(HeartFailure.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND HeartFailure.patient_id = QualifyingEncounter.patient_id)
),
"AHA.Moderate or Severe LVSD Findings" AS (
(SELECT patient_id, resource FROM "Observation: Ejection Fraction" AS EjectionFraction WHERE quantity_compare(parse_quantity(EjectionFraction.value), parse_quantity('{"value": 40.0, "unit": "%", "system": "http://unitsofmeasure.org"}'), '<=') AND array_contains(['final', 'amended', 'corrected'], EjectionFraction.status)) UNION (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Moderate or Severe LVSD (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Moderate or Severe LVSD (qicore-condition-encounter-diagnosis)" UNION (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Left ventricular systolic dysfunction (disorder) (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Left ventricular systolic dysfunction (disorder) (qicore-condition-encounter-diagnosis)") AS LVSDDiagnosis WHERE in_valueset(LVSDDiagnosis.resource, 'severity', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1092'))) AS ModerateOrSevereLVSD WHERE (fhirpath_bool(ModerateOrSevereLVSD.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(ModerateOrSevereLVSD.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(ModerateOrSevereLVSD.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(ModerateOrSevereLVSD.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"AHA.Qualifying Outpatient Encounter During Measurement Period" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Outpatient Consultation" UNION SELECT patient_id, resource FROM "Encounter: Nursing Facility Visit" UNION SELECT patient_id, resource FROM "Encounter: Care Services in Long Term Residential Facility" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Patient Provider Interaction") AS ValidEncounter WHERE CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(ValidEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(ValidEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND fhirpath_text(ValidEncounter.resource, 'status') = 'finished'
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS (
SELECT * FROM "AHA.Heart Failure Outpatient Encounter" AS HFOutpatientEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Moderate or Severe LVSD Findings") AS LVSDFindings WHERE intervalStart(COALESCE(CASE WHEN fhirpath_text(LVSDFindings.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')), fhirpath_text(LVSDFindings.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LVSDFindings.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, CASE WHEN fhirpath_text(LVSDFindings.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(LVSDFindings.resource, 'effective')), '{') THEN fhirpath_text(LVSDFindings.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(LVSDFindings.resource, 'effective'), fhirpath_text(LVSDFindings.resource, 'effective'), TRUE, TRUE) END)) < intervalEnd(fhirpath_text(HFOutpatientEncounter.resource, 'period')) AND LVSDFindings.patient_id = HFOutpatientEncounter.patient_id)
),
"AHA.Is Adults With Two Qualifying Outpatient Encounters and One Heart Failure Outpatient Encounter During the Measurement Period" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END >= 18 AND EXISTS (SELECT * FROM "AHA.Qualifying Outpatient Encounter During Measurement Period" AS Encounter1 WHERE Encounter1.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Qualifying Outpatient Encounter During Measurement Period") AS Encounter2 WHERE NOT CASE WHEN fhirpath_text(Encounter2.resource, 'id') IS NULL AND fhirpath_text(Encounter1.resource, 'id') IS NULL THEN TRUE WHEN fhirpath_text(Encounter2.resource, 'id') IS NULL OR fhirpath_text(Encounter1.resource, 'id') IS NULL THEN FALSE ELSE fhirpath_text(Encounter2.resource, 'id') = fhirpath_text(Encounter1.resource, 'id') END AND Encounter2.patient_id = Encounter1.patient_id)) AND EXISTS (SELECT 1 FROM "AHA.Heart Failure Outpatient Encounter" AS sub WHERE sub.patient_id = p.patient_id)
),
"AHA.Has Heart Transplant" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Procedure: Heart Transplant" AS HeartTransplant WHERE HeartTransplant.patient_id = p.patient_id AND fhirpath_text(HeartTransplant.resource, 'status') = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE intervalStart(CASE WHEN fhirpath_text(HeartTransplant.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartTransplant.resource, 'performed')), '{') THEN fhirpath_text(HeartTransplant.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HeartTransplant.resource, 'performed'), fhirpath_text(HeartTransplant.resource, 'performed'), TRUE, TRUE) END) < intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = HeartTransplant.patient_id))
),
"AHA.Has Heart Transplant Complications" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Heart Transplant Complications (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Heart Transplant Complications (qicore-condition-problems-health-concerns)") AS HeartTransplantComplications WHERE HeartTransplantComplications.patient_id = p.patient_id AND (fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(HeartTransplantComplications.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE cqlBefore(CAST(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'recordedDate'), intervalStart(CASE WHEN fhirpath_text(HeartTransplantComplications.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')), fhirpath_text(HeartTransplantComplications.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AS VARCHAR), CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS VARCHAR)) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = HeartTransplantComplications.patient_id))
),
"AHA.Has Left Ventricular Assist Device" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Procedure: Left Ventricular Assist Device Placement" AS LVADOutpatient WHERE LVADOutpatient.patient_id = p.patient_id AND fhirpath_text(LVADOutpatient.resource, 'status') = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE intervalStart(CASE WHEN fhirpath_text(LVADOutpatient.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(LVADOutpatient.resource, 'performed')), '{') THEN fhirpath_text(LVADOutpatient.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(LVADOutpatient.resource, 'performed'), fhirpath_text(LVADOutpatient.resource, 'performed'), TRUE, TRUE) END) < intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = LVADOutpatient.patient_id))
),
"AHA.Has Left Ventricular Assist Device Complications" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Left Ventricular Assist Device Complications (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Left Ventricular Assist Device Complications (qicore-condition-problems-health-concerns)") AS LVADComplications WHERE LVADComplications.patient_id = p.patient_id AND (fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(LVADComplications.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE cqlBefore(CAST(COALESCE(fhirpath_text(LVADComplications.resource, 'recordedDate'), intervalStart(CASE WHEN fhirpath_text(LVADComplications.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')), fhirpath_text(LVADComplications.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AS VARCHAR), CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS VARCHAR)) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = LVADComplications.patient_id))
),
"Denominator Exclusions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "AHA.Has Heart Transplant" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AHA.Has Heart Transplant Complications" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AHA.Has Left Ventricular Assist Device" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "AHA.Has Left Ventricular Assist Device Complications" AS sub WHERE sub.patient_id = p.patient_id)
),
"Has Allergy or Intolerance to Beta Blocker Therapy Ingredient" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "AllergyIntolerance: Beta Blocker Therapy Ingredient" UNION SELECT patient_id, resource FROM "AllergyIntolerance: Substance with beta adrenergic receptor antagonist mechanism of action (substance)") AS BetaBlockerAllergyIntolerance WHERE BetaBlockerAllergyIntolerance.patient_id = p.patient_id AND intervalOverlaps(intervalFromBounds(CAST(intervalStart(CASE WHEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset')), '{') THEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset'), TRUE, TRUE) END) AS VARCHAR), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'lastOccurrence'), TRUE, TRUE), fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart(CASE WHEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset')), '{') THEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset'), TRUE, TRUE) END) AS VARCHAR), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'lastOccurrence'), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) > COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical'' and code=''active'').exists()') AND fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-verification'' and code=''confirmed'').exists()') AND (NOT (fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus') IS NOT NULL) OR NOT fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical'' and code=''inactive'').exists()') OR fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical'' and code=''active'').exists()')))
),
"Has Arrhythmia Diagnosis" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Condition: Arrhythmia (qicore-condition-problems-health-concerns)" AS ArrhythmiaAlias WHERE ArrhythmiaAlias.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(ArrhythmiaAlias.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ArrhythmiaAlias.resource, 'onsetDateTime'), fhirpath_text(ArrhythmiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(ArrhythmiaAlias.resource, 'recordedDate')), fhirpath_text(ArrhythmiaAlias.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ArrhythmiaAlias.resource, 'onsetDateTime'), fhirpath_text(ArrhythmiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(ArrhythmiaAlias.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ArrhythmiaAlias.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ArrhythmiaAlias.resource, 'onsetDateTime'), fhirpath_text(ArrhythmiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(ArrhythmiaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ArrhythmiaAlias.resource, 'onsetDateTime'), fhirpath_text(ArrhythmiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(ArrhythmiaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(ArrhythmiaAlias.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ArrhythmiaAlias.resource, 'onsetDateTime'), fhirpath_text(ArrhythmiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(ArrhythmiaAlias.resource, 'recordedDate')), fhirpath_text(ArrhythmiaAlias.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ArrhythmiaAlias.resource, 'onsetDateTime'), fhirpath_text(ArrhythmiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(ArrhythmiaAlias.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ArrhythmiaAlias.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ArrhythmiaAlias.resource, 'onsetDateTime'), fhirpath_text(ArrhythmiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(ArrhythmiaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ArrhythmiaAlias.resource, 'onsetDateTime'), fhirpath_text(ArrhythmiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(ArrhythmiaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND (fhirpath_bool(ArrhythmiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(ArrhythmiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(ArrhythmiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(ArrhythmiaAlias.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND (fhirpath_bool(ArrhythmiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(ArrhythmiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(ArrhythmiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(ArrhythmiaAlias.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Has Asthma Diagnosis" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Condition: Asthma (qicore-condition-problems-health-concerns)" AS AsthmaAlias WHERE AsthmaAlias.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(AsthmaAlias.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(AsthmaAlias.resource, 'onsetDateTime'), fhirpath_text(AsthmaAlias.resource, 'onsetPeriod.start'), fhirpath_text(AsthmaAlias.resource, 'recordedDate')), fhirpath_text(AsthmaAlias.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(AsthmaAlias.resource, 'onsetDateTime'), fhirpath_text(AsthmaAlias.resource, 'onsetPeriod.start'), fhirpath_text(AsthmaAlias.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(AsthmaAlias.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(AsthmaAlias.resource, 'onsetDateTime'), fhirpath_text(AsthmaAlias.resource, 'onsetPeriod.start'), fhirpath_text(AsthmaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(AsthmaAlias.resource, 'onsetDateTime'), fhirpath_text(AsthmaAlias.resource, 'onsetPeriod.start'), fhirpath_text(AsthmaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(AsthmaAlias.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(AsthmaAlias.resource, 'onsetDateTime'), fhirpath_text(AsthmaAlias.resource, 'onsetPeriod.start'), fhirpath_text(AsthmaAlias.resource, 'recordedDate')), fhirpath_text(AsthmaAlias.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(AsthmaAlias.resource, 'onsetDateTime'), fhirpath_text(AsthmaAlias.resource, 'onsetPeriod.start'), fhirpath_text(AsthmaAlias.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(AsthmaAlias.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(AsthmaAlias.resource, 'onsetDateTime'), fhirpath_text(AsthmaAlias.resource, 'onsetPeriod.start'), fhirpath_text(AsthmaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(AsthmaAlias.resource, 'onsetDateTime'), fhirpath_text(AsthmaAlias.resource, 'onsetPeriod.start'), fhirpath_text(AsthmaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND (fhirpath_bool(AsthmaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(AsthmaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(AsthmaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(AsthmaAlias.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND (fhirpath_bool(AsthmaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(AsthmaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(AsthmaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(AsthmaAlias.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Has Atrioventricular Block Diagnosis" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Condition: Atrioventricular Block (qicore-condition-problems-health-concerns)" AS AtrioventricularBlock WHERE AtrioventricularBlock.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(AtrioventricularBlock.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(AtrioventricularBlock.resource, 'onsetDateTime'), fhirpath_text(AtrioventricularBlock.resource, 'onsetPeriod.start'), fhirpath_text(AtrioventricularBlock.resource, 'recordedDate')), fhirpath_text(AtrioventricularBlock.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(AtrioventricularBlock.resource, 'onsetDateTime'), fhirpath_text(AtrioventricularBlock.resource, 'onsetPeriod.start'), fhirpath_text(AtrioventricularBlock.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(AtrioventricularBlock.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(AtrioventricularBlock.resource, 'onsetDateTime'), fhirpath_text(AtrioventricularBlock.resource, 'onsetPeriod.start'), fhirpath_text(AtrioventricularBlock.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(AtrioventricularBlock.resource, 'onsetDateTime'), fhirpath_text(AtrioventricularBlock.resource, 'onsetPeriod.start'), fhirpath_text(AtrioventricularBlock.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(AtrioventricularBlock.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(AtrioventricularBlock.resource, 'onsetDateTime'), fhirpath_text(AtrioventricularBlock.resource, 'onsetPeriod.start'), fhirpath_text(AtrioventricularBlock.resource, 'recordedDate')), fhirpath_text(AtrioventricularBlock.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(AtrioventricularBlock.resource, 'onsetDateTime'), fhirpath_text(AtrioventricularBlock.resource, 'onsetPeriod.start'), fhirpath_text(AtrioventricularBlock.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(AtrioventricularBlock.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(AtrioventricularBlock.resource, 'onsetDateTime'), fhirpath_text(AtrioventricularBlock.resource, 'onsetPeriod.start'), fhirpath_text(AtrioventricularBlock.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(AtrioventricularBlock.resource, 'onsetDateTime'), fhirpath_text(AtrioventricularBlock.resource, 'onsetPeriod.start'), fhirpath_text(AtrioventricularBlock.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND (fhirpath_bool(AtrioventricularBlock.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(AtrioventricularBlock.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(AtrioventricularBlock.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(AtrioventricularBlock.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND (fhirpath_bool(AtrioventricularBlock.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(AtrioventricularBlock.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(AtrioventricularBlock.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(AtrioventricularBlock.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Has Beta Blocker Therapy for LVSD Ordered" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "MedicationRequest: Beta Blocker Therapy for LVSD" AS BetaBlockerOrdered WHERE BetaBlockerOrdered.patient_id = p.patient_id AND EXISTS (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE CAST(LEFT(REPLACE(CAST(fhirpath_text(BetaBlockerOrdered.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(fhirpath_text(BetaBlockerOrdered.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND array_contains(['active', 'completed'], fhirpath_text(BetaBlockerOrdered.resource, 'status')) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], fhirpath_text(BetaBlockerOrdered.resource, 'intent')) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = BetaBlockerOrdered.patient_id))
),
"Has Bradycardia Diagnosis" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Condition: Bradycardia (qicore-condition-problems-health-concerns)" AS BradycardiaAlias WHERE BradycardiaAlias.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(BradycardiaAlias.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BradycardiaAlias.resource, 'onsetDateTime'), fhirpath_text(BradycardiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaAlias.resource, 'recordedDate')), fhirpath_text(BradycardiaAlias.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BradycardiaAlias.resource, 'onsetDateTime'), fhirpath_text(BradycardiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaAlias.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BradycardiaAlias.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BradycardiaAlias.resource, 'onsetDateTime'), fhirpath_text(BradycardiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BradycardiaAlias.resource, 'onsetDateTime'), fhirpath_text(BradycardiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(BradycardiaAlias.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BradycardiaAlias.resource, 'onsetDateTime'), fhirpath_text(BradycardiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaAlias.resource, 'recordedDate')), fhirpath_text(BradycardiaAlias.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BradycardiaAlias.resource, 'onsetDateTime'), fhirpath_text(BradycardiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaAlias.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BradycardiaAlias.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BradycardiaAlias.resource, 'onsetDateTime'), fhirpath_text(BradycardiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BradycardiaAlias.resource, 'onsetDateTime'), fhirpath_text(BradycardiaAlias.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND (fhirpath_bool(BradycardiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(BradycardiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(BradycardiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(BradycardiaAlias.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND (fhirpath_bool(BradycardiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(BradycardiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(BradycardiaAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(BradycardiaAlias.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Has Cardiac Pacer Device Implanted" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Procedure: Cardiac Pacer" AS ImplantedCardiacPacer WHERE ImplantedCardiacPacer.patient_id = p.patient_id AND fhirpath_text(ImplantedCardiacPacer.resource, 'status') = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE intervalStart(CASE WHEN fhirpath_text(ImplantedCardiacPacer.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ImplantedCardiacPacer.resource, 'performed')), '{') THEN fhirpath_text(ImplantedCardiacPacer.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ImplantedCardiacPacer.resource, 'performed'), fhirpath_text(ImplantedCardiacPacer.resource, 'performed'), TRUE, TRUE) END) < intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = ImplantedCardiacPacer.patient_id))
),
"Has Consecutive Heart Rates Less than 50" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT HeartRate.patient_id, CAST(HeartRate.resource AS VARCHAR) AS resource FROM "Observation (us-core-heart-rate)" AS HeartRate CROSS JOIN (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE HeartRate.patient_id = p.patient_id AND intervalIncludes(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period'), CASE WHEN fhirpath_text(HeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartRate.resource, 'effective')), '{') THEN fhirpath_text(HeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HeartRate.resource, 'effective'), fhirpath_text(HeartRate.resource, 'effective'), TRUE, TRUE) END) AND array_contains(['final', 'amended', 'corrected'], fhirpath_text(HeartRate.resource, 'status')) AND TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(HeartRate.resource, 'value')), '{') THEN json_extract_string(fhirpath_text(HeartRate.resource, 'value'), '$.value') ELSE fhirpath_text(HeartRate.resource, 'value') END AS DOUBLE) < 50.0 AND TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text((SELECT resource FROM "Observation (us-core-heart-rate)" AS MostRecentPriorHeartRate WHERE intervalIncludes(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period'), CASE WHEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), TRUE, TRUE) END) AND intervalBefore(CASE WHEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(HeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartRate.resource, 'effective')), '{') THEN fhirpath_text(HeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HeartRate.resource, 'effective'), fhirpath_text(HeartRate.resource, 'effective'), TRUE, TRUE) END) AND MostRecentPriorHeartRate.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(MostRecentPriorHeartRate.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value')), '{') THEN json_extract_string(fhirpath_text((SELECT resource FROM "Observation (us-core-heart-rate)" AS MostRecentPriorHeartRate WHERE intervalIncludes(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period'), CASE WHEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), TRUE, TRUE) END) AND intervalBefore(CASE WHEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(HeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartRate.resource, 'effective')), '{') THEN fhirpath_text(HeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HeartRate.resource, 'effective'), fhirpath_text(HeartRate.resource, 'effective'), TRUE, TRUE) END) AND MostRecentPriorHeartRate.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(MostRecentPriorHeartRate.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value'), '$.value') ELSE fhirpath_text((SELECT resource FROM "Observation (us-core-heart-rate)" AS MostRecentPriorHeartRate WHERE intervalIncludes(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period'), CASE WHEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), TRUE, TRUE) END) AND intervalBefore(CASE WHEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(HeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartRate.resource, 'effective')), '{') THEN fhirpath_text(HeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HeartRate.resource, 'effective'), fhirpath_text(HeartRate.resource, 'effective'), TRUE, TRUE) END) AND MostRecentPriorHeartRate.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRate.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRate.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(MostRecentPriorHeartRate.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value') END AS DOUBLE) < 50.0 AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = HeartRate.patient_id)
),
"Has Diagnosis of Allergy or Intolerance to Beta Blocker Therapy" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Allergy to Beta Blocker Therapy (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Intolerance to Beta Blocker Therapy (qicore-condition-problems-health-concerns)") AS BetaBlockerAllergyOrIntoleranceDiagnosis WHERE BetaBlockerAllergyOrIntoleranceDiagnosis.patient_id = p.patient_id AND intervalOverlaps(CASE WHEN fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) > COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND (fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND (fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Has Diagnosis of Cardiac Pacer in Situ" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Condition: Cardiac Pacer in Situ (qicore-condition-problems-health-concerns)" AS CardiacPacerDiagnosis WHERE CardiacPacerDiagnosis.patient_id = p.patient_id AND intervalOverlaps(CASE WHEN fhirpath_text(CardiacPacerDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), fhirpath_text(CardiacPacerDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(CardiacPacerDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), fhirpath_text(CardiacPacerDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) > COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND (fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(CardiacPacerDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND (fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(CardiacPacerDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Atrioventricular Block without Cardiac Pacer" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Atrioventricular Block Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) AND NOT EXISTS (SELECT 1 FROM "Has Diagnosis of Cardiac Pacer in Situ" AS sub WHERE sub.patient_id = p.patient_id) AND NOT EXISTS (SELECT 1 FROM "Has Cardiac Pacer Device Implanted" AS sub WHERE sub.patient_id = p.patient_id)
),
"Has Hypotension Diagnosis" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Condition: Hypotension (qicore-condition-problems-health-concerns)" AS HypotensionAlias WHERE HypotensionAlias.patient_id = p.patient_id AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(HypotensionAlias.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HypotensionAlias.resource, 'onsetDateTime'), fhirpath_text(HypotensionAlias.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionAlias.resource, 'recordedDate')), fhirpath_text(HypotensionAlias.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HypotensionAlias.resource, 'onsetDateTime'), fhirpath_text(HypotensionAlias.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionAlias.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HypotensionAlias.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HypotensionAlias.resource, 'onsetDateTime'), fhirpath_text(HypotensionAlias.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HypotensionAlias.resource, 'onsetDateTime'), fhirpath_text(HypotensionAlias.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(HypotensionAlias.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HypotensionAlias.resource, 'onsetDateTime'), fhirpath_text(HypotensionAlias.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionAlias.resource, 'recordedDate')), fhirpath_text(HypotensionAlias.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HypotensionAlias.resource, 'onsetDateTime'), fhirpath_text(HypotensionAlias.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionAlias.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HypotensionAlias.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HypotensionAlias.resource, 'onsetDateTime'), fhirpath_text(HypotensionAlias.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HypotensionAlias.resource, 'onsetDateTime'), fhirpath_text(HypotensionAlias.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionAlias.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND (fhirpath_bool(HypotensionAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HypotensionAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HypotensionAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(HypotensionAlias.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND (fhirpath_bool(HypotensionAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HypotensionAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HypotensionAlias.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(HypotensionAlias.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"Has Medical or Patient Reason for Not Ordering Beta Blocker for LVSD" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "MedicationRequest: Beta Blocker Therapy for LVSD (medicationnotrequested)" AS NoBetaBlockerOrdered WHERE NoBetaBlockerOrdered.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE CAST(LEFT(REPLACE(CAST(fhirpath_text(NoBetaBlockerOrdered.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(fhirpath_text(NoBetaBlockerOrdered.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = NoBetaBlockerOrdered.patient_id))
),
"Denominator Exceptions" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Consecutive Heart Rates Less than 50" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Medical or Patient Reason for Not Ordering Beta Blocker for LVSD" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Arrhythmia Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Hypotension Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Asthma Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Diagnosis of Allergy or Intolerance to Beta Blocker Therapy" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Bradycardia Diagnosis" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Allergy or Intolerance to Beta Blocker Therapy Ingredient" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Atrioventricular Block without Cardiac Pacer" AS sub WHERE sub.patient_id = p.patient_id)
),
"Initial Population" AS (
SELECT * FROM "AHA.Is Adults With Two Qualifying Outpatient Encounters and One Heart Failure Outpatient Encounter During the Measurement Period"
),
"Denominator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Initial Population" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id)
),
"Is Currently Taking Beta Blocker Therapy for LVSD" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "MedicationRequest: Beta Blocker Therapy for LVSD" AS ActiveBetaBlocker WHERE ActiveBetaBlocker.patient_id = p.patient_id AND intervalOverlaps(list_extract(from_json(collapse_intervals(to_json(list_transform(from_json(fhirpath(ActiveBetaBlocker.resource, 'dosageInstruction.timing.repeat.bounds'), '["VARCHAR"]'), _lt_DoseTime -> CASE WHEN _lt_DoseTime IS NULL THEN NULL WHEN starts_with(LTRIM(_lt_DoseTime), '{') THEN _lt_DoseTime ELSE intervalFromBounds(CAST(_lt_DoseTime AS VARCHAR), CAST(_lt_DoseTime AS VARCHAR), TRUE, TRUE) END))), '["VARCHAR"]'), 1), fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(list_extract(from_json(collapse_intervals(to_json(list_transform(from_json(fhirpath(ActiveBetaBlocker.resource, 'dosageInstruction.timing.repeat.bounds'), '["VARCHAR"]'), _lt_DoseTime -> CASE WHEN _lt_DoseTime IS NULL THEN NULL WHEN starts_with(LTRIM(_lt_DoseTime), '{') THEN _lt_DoseTime ELSE intervalFromBounds(CAST(_lt_DoseTime AS VARCHAR), CAST(_lt_DoseTime AS VARCHAR), TRUE, TRUE) END))), '["VARCHAR"]'), 1)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) > COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND array_contains(['active', 'completed'], fhirpath_text(ActiveBetaBlocker.resource, 'status')) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], fhirpath_text(ActiveBetaBlocker.resource, 'intent')))
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Beta Blocker Therapy for LVSD Ordered" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Is Currently Taking Beta Blocker Therapy for LVSD" AS sub WHERE sub.patient_id = p.patient_id)
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Denominator Exceptions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exceptions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Denominator Exceptions" ON p.patient_id = "Denominator Exceptions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
